import React, { useEffect, useState } from "react";
import "./Admin.css";
import { use } from "react";

const Admin = () => {
  const [stats, setStats] = useState([]);
  const [news, setNews] = useState([]);
  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    date: "",
    category: "IT",
    image: ""
  });
  const [newsForm, setNewsForm] = useState({
    title: "",
    content: "",
    date: ""
  });

  const [editingEvent, seteditingEvent] = useState(null);

  const loadStats = () => {
    fetch("http://localhost:5000/admin/stats")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setStats(data);
        else setStats([]);
      });
  };

  useEffect(() => {
    loadStats();
    loadNews();
  }, []);

  const loadNews = () => {
    fetch("http://localhost:5000/admin/news")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setNews(data);
        else setNews([]);
      });
  };

  const handleDeleteNews = async (id) => {
    if (!window.confirm("Видалити новину?")) return;

    try {
      const res = await fetch(`http://localhost:5000/admin/news/${id}`, {
        method: "DELETE"
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      setNews(prev => prev.filter(n => n.id !== id));

    } catch (err) {
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Видалити подію?")) return;

    try {
      const res = await fetch(`http://localhost:5000/events/${id}`, {
        method: "DELETE"
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      setStats(prev => prev.filter(event => event.id !== id));

    } catch (err) {
      console.error(err);
    }
  };

  // =========================
  // ➕ ДОБАВИТЬ СОБЫТИЕ
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const res = await fetch("http://localhost:5000/admin/events", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(form)
    });

    const data = await res.json();

    if (!res.ok) {
      alert(data.error);
      return;
    }

    alert("Подія створена");

    setForm({
      title: "",
      description: "",
      location: "",
      date: "",
      category: "IT",
      image: ""
    });

    loadStats();
  };

  // =========================
  // 📰 ДОБАВИТЬ НОВОСТЬ
  // =========================
  const handleAddNews = async (e) => {
    e.preventDefault();

    if (!newsForm.title || !newsForm.content || !newsForm.date) {
      alert("Заповни всі поля новини");
      return;
    }

    try {
      const res = await fetch("http://localhost:5000/admin/news", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(newsForm)
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      alert("Новину додано 📰");

      setNewsForm({
        title: "",
        content: "",
        date: ""
      });

    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="admin-page">

      <h1>Адмін панель</h1>

      {/* ========================= */}
      {/* 📊 СТАТИСТИКА */}
      {/* ========================= */}
      <div className="admin-stats">
        <h2>Статистика подій</h2>

        {Array.isArray(stats) && stats.length > 0 ? (
          stats.map(event => (
            <div key={event.id} className="stat-card">
              <h3>{event.title}</h3>
              <p>Реєстрацій: {event.registrations}</p>

              <button
                className="delete-btn"
                onClick={() => handleDelete(event.id)}
              >
                Видалити
              </button>
            </div>
          ))
        ) : (
          <p>Немає даних</p>
        )}
      </div>

      {/* ========================= */}
      {/* ➕ ДОБАВИТЬ СОБЫТИЕ */}
      {/* ========================= */}
      <div className="admin-form">
        <h2>Додати подію</h2>

        <form onSubmit={handleSubmit}>
          <input
            placeholder="Назва"
            value={form.title}
            onChange={(e) =>
              setForm({ ...form, title: e.target.value })
            }
          />

          <input
            placeholder="Опис"
            value={form.description}
            onChange={(e) =>
              setForm({ ...form, description: e.target.value })
            }
          />

          <input
            placeholder="Місто"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="datetime-local"
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <select
            value={form.category}
            onChange={(e) =>
              setForm({ ...form, category: e.target.value })
            }
          >
            <option>IT</option>
            <option>Business</option>
            <option>Design</option>
            <option>Marketing</option>
            <option>Education</option>
          </select>

          <input
            placeholder="URL картинки"
            value={form.image}
            onChange={(e) =>
              setForm({ ...form, image: e.target.value })
            }
          />

          <button type="submit">Створити</button>
        </form>
      </div>

      <div className="admin-stats">
        <h2>Новини</h2>

        {news.length > 0 ? (
          news.map(item => (
            <div key={item.id} className="stat-card">
              <div>
                <h3>{item.title}</h3>
                <p>
                  {new Date(item.date).toLocaleDateString()}
                </p>
              </div>

              <button
                className="delete-btn"
                onClick={() => handleDeleteNews(item.id)}
              >
                Видалити
              </button>
            </div>
          ))
        ) : (
          <p>Новин немає</p>
        )}
      </div>

      <div className="admin-form">
        <h2>Додати новину</h2>

        <form onSubmit={handleAddNews}>
          <input
            placeholder="Заголовок"
            value={newsForm.title}
            onChange={(e) =>
              setNewsForm({ ...newsForm, title: e.target.value })
            }
          />

          <textarea
            placeholder="Текст новини"
            value={newsForm.content}
            onChange={(e) =>
              setNewsForm({ ...newsForm, content: e.target.value })
            }
          />

          <input
            type="datetime-local"
            value={newsForm.date}
            onChange={(e) =>
              setNewsForm({ ...newsForm, date: e.target.value })
            }
          />

          <button type="submit">Додати новину</button>
        </form>
      </div>

    </div>
  );
};

export default Admin;
